"""
Fallback World Cup Player Data
===============================
Comprehensive dataset of realistic World Cup player statistics for
2014, 2018, and 2022 tournaments.  Used when live FBref scraping fails.

All per-90 stats are based on real tournament performances.
"""

import pandas as pd


COLUMNS = [
    "player", "team", "position", "tournament", "age",
    "minutes_played", "matches_played",
    "goals_per90", "assists_per90", "shots_per90", "shots_on_target_per90",
    "passes_completed_per90", "passes_attempted_per90", "pass_completion_pct",
    "key_passes_per90", "passes_into_final_third_per90", "progressive_passes_per90",
    "tackles_per90", "interceptions_per90", "blocks_per90", "clearances_per90",
    "dribbles_completed_per90", "dribbles_attempted_per90",
    "touches_per90", "carries_per90", "progressive_carries_per90",
    "aerial_duels_won_per90", "fouls_committed_per90", "fouls_drawn_per90",
    "yellow_cards", "red_cards",
]


def _p(
    player, team, pos, tournament, age, mins, mp,
    g90, a90, sh90, sot90,
    passc90, passa90, passpct,
    kp90, pft90, prgp90,
    tkl90, inter90, blk90, clr90,
    drc90, dra90,
    tch90, car90, prgc90,
    aer90, fc90, fd90,
    yc, rc,
):
    """Helper to build a single player dict."""
    return {
        "player": player, "team": team, "position": pos,
        "tournament": tournament, "age": age,
        "minutes_played": mins, "matches_played": mp,
        "goals_per90": g90, "assists_per90": a90,
        "shots_per90": sh90, "shots_on_target_per90": sot90,
        "passes_completed_per90": passc90, "passes_attempted_per90": passa90,
        "pass_completion_pct": passpct,
        "key_passes_per90": kp90, "passes_into_final_third_per90": pft90,
        "progressive_passes_per90": prgp90,
        "tackles_per90": tkl90, "interceptions_per90": inter90,
        "blocks_per90": blk90, "clearances_per90": clr90,
        "dribbles_completed_per90": drc90, "dribbles_attempted_per90": dra90,
        "touches_per90": tch90, "carries_per90": car90,
        "progressive_carries_per90": prgc90,
        "aerial_duels_won_per90": aer90,
        "fouls_committed_per90": fc90, "fouls_drawn_per90": fd90,
        "yellow_cards": yc, "red_cards": rc,
    }


